import { IMessageDataWrapper, IMessageParser } from '@nitrots/nitro-renderer';

export type TradeSlot = {
hasItem: boolean;
inventoryRowId?: number;
itemId?: number;
name?: string;
icon?: string;
rarity?: string;
type?: string;
quantity?: number;
durability?: number;
maxDurability?: number;
};

export class TradeUpdateParser implements IMessageParser
{
private _sessionId = 0;
private _aConfirmed = false;
private _bConfirmed = false;
private _aSlots: TradeSlot[] = [];
private _bSlots: TradeSlot[] = [];

public flush(): boolean
{
this._sessionId = 0;
this._aConfirmed = false;
this._bConfirmed = false;
this._aSlots = [];
this._bSlots = [];
return true;
}

public parse(wrapper: IMessageDataWrapper): boolean
{
if(!wrapper) return false;

// Must match TradeUpdateComposer.java
this._sessionId = wrapper.readInt();

this._aConfirmed = wrapper.readBoolean();
this._bConfirmed = wrapper.readBoolean();

const aCount = wrapper.readInt();
this._aSlots = this.readSlots(wrapper, aCount);

const bCount = wrapper.readInt();
this._bSlots = this.readSlots(wrapper, bCount);

return true;
}

private readSlots(wrapper: IMessageDataWrapper, count: number): TradeSlot[]
{
const out: TradeSlot[] = [];

for(let i = 0; i < count; i++)
{
const hasItem = wrapper.readBoolean();

if(!hasItem)
{
out.push({ hasItem: false });
continue;
}

out.push({
hasItem: true,
inventoryRowId: wrapper.readInt(),
itemId: wrapper.readInt(),
name: wrapper.readString(),
icon: wrapper.readString(),
rarity: wrapper.readString(),
type: wrapper.readString(),
quantity: wrapper.readInt(),
durability: wrapper.readInt(),
maxDurability: wrapper.readInt()
});
}

return out;
}

public get sessionId(): number { return this._sessionId; }
public get aConfirmed(): boolean { return this._aConfirmed; }
public get bConfirmed(): boolean { return this._bConfirmed; }
public get aSlots(): TradeSlot[] { return this._aSlots; }
public get bSlots(): TradeSlot[] { return this._bSlots; }
}
